#include <stdio.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        int prev, cur;
        for(int i=0;i<N;i++){
            scanf("%d", &cur);
            if(i==0){
                printf("%d", cur);
                prev = cur;
            } else if(cur != prev){
                printf(" %d", cur);
                prev = cur;
            }
        }
        if(T) printf("\n");
    }
    return 0;
}

